function getLockedSupabaseConfigValue(value) {
  const text = String(value || "").trim();
  const isPlaceholder =
    !text ||
    text.includes("YOUR_PROJECT_REF") ||
    text.includes("YOUR_SUPABASE") ||
    text.includes("PASTE_SUPABASE") ||
    text.includes("PASTE_");

  return isPlaceholder ? "" : text;
}

const state = {
  supabase: null,
  session: null,
  view: "dashboard",
  data: {
    jobs: [],
    clients: [],
    costTrackers: [],
    invoices: [],
    employees: [],
    assignments: [],
    timesheets: [],
    documents: []
  }
};

const $ = (selector) => document.querySelector(selector);
const $$ = (selector) => Array.from(document.querySelectorAll(selector));

document.addEventListener("DOMContentLoaded", init);

function init() {
  bindEvents();
  initializeCostInvoiceBuilders();
  loadConfigIntoSettings();
  initSupabase();

  if (state.supabase) {
    checkSession();
  } else {
    updateConnectionWarning();
  }
}

function bindIfExists(selector, eventName, handler) {
  const element = $(selector);
  if (element) element.addEventListener(eventName, handler);
}

function bindEvents() {
  bindIfExists("#loginForm", "submit", handleLogin);
  bindIfExists("#signOutBtn", "click", handleSignOut);
  bindIfExists("#refreshBtn", "click", loadAllData);
  bindIfExists("#quickCreateJobBtn", "click", () => showView("jobs"));

  // Supabase settings are intentionally locked in code for GitHub Pages.
  // There is no visible settings button for users.
  const globalSearch = $("#globalSearch");
  if (globalSearch) globalSearch.addEventListener("input", renderAll);

  $$(".table-search").forEach((input) => {
    input.addEventListener("input", renderAll);
  });

  $$(".nav-btn").forEach((button) => {
    button.addEventListener("click", () => showView(button.dataset.view));
  });

  $$("[data-view-jump]").forEach((button) => {
    button.addEventListener("click", () => showView(button.dataset.viewJump));
  });

  bindIfExists("#jobForm", "submit", handleCreateJob);
  bindIfExists("#costTrackerForm", "submit", handleSaveCostTracker);
  bindIfExists("#invoiceForm", "submit", handleCreateInvoice);
  bindIfExists("#employeeForm", "submit", handleCreateEmployee);
  bindIfExists("#assignmentForm", "submit", handleCreateAssignment);
  bindIfExists("#timesheetForm", "submit", handleCreateTimesheet);
}

function getConfig() {
  // Kept only for compatibility with older saved browsers.
  // The active Supabase connection now comes from locked constants below.
  return {};
}

function saveConfig(_config) {
  // Settings are locked in code; users cannot change Supabase connection values.
}

function loadConfigIntoSettings() {
  // Settings UI was removed intentionally.
}

function initSupabase() {
  const url = getLockedSupabaseConfigValue(LOCKED_SUPABASE_PROJECT_URL);
  const anonKey = getLockedSupabaseConfigValue(LOCKED_SUPABASE_ANON_KEY);

  if (!url || !anonKey) {
    state.supabase = null;
    return;
  }

  if (!window.supabase || !window.supabase.createClient) {
    showToast("Supabase library did not load. Check your internet connection.", true);
    state.supabase = null;
    return;
  }

  state.supabase = window.supabase.createClient(url, anonKey, {
    auth: {
      persistSession: true,
      autoRefreshToken: true,
      detectSessionInUrl: true
    }
  });
}

function updateConnectionWarning() {
  // Keep the login screen clean. Connection details are locked in app.js,
  // so users should only see the email/password form.
  const warning = $("#setupWarning");
  if (warning) warning.classList.add("hidden");
}

function openSettings() {
  showToast("Supabase connection settings are locked in the website code.", true);
}

function saveSettings() {
  showToast("Supabase connection settings are locked in the website code.", true);
}

function clearSettings() {
  showToast("Supabase connection settings are locked in the website code.", true);
}

async function checkSession() {
  if (!state.supabase) return;

  const { data, error } = await state.supabase.auth.getSession();

  if (error) {
    showToast(error.message, true);
    return;
  }

  state.session = data.session || null;
  showCorrectScreen();

  if (state.session) {
    await loadAllData();
  }

  state.supabase.auth.onAuthStateChange(async (_event, session) => {
    state.session = session;
    showCorrectScreen();

    if (session) {
      await loadAllData();
    }
  });
}

function showCorrectScreen() {
  $("#authScreen").classList.toggle("hidden", Boolean(state.session));
  $("#appShell").classList.toggle("hidden", !state.session);
}

async function handleLogin(event) {
  event.preventDefault();

  if (!state.supabase) {
    updateConnectionWarning();
    showToast("Unable to connect right now. Refresh the page and try again.", true);
    return;
  }

  const email = $("#loginEmail").value.trim();
  const password = $("#loginPassword").value;

  const { error } = await state.supabase.auth.signInWithPassword({
    email,
    password
  });

  if (error) {
    showToast(error.message, true);
    return;
  }

  showToast("Signed in.");
}

async function handleSignOut() {
  if (!state.supabase) return;

  await state.supabase.auth.signOut();
  state.session = null;
  showCorrectScreen();
}

async function loadAllData() {
  if (!state.supabase || !state.session) return;

  try {
    const [
      clients,
      jobs,
      costTrackers,
      invoices,
      employees,
      assignments,
      timesheets,
      documents
    ] = await Promise.all([
      selectTable("clients", "*", "company_name", true),
      selectTable("jobs", "*", "last_synced_at", false),
      selectTable("cost_trackers", "*", "last_synced_at", false),
      selectTable("invoices", "*", "invoice_date", false),
      selectTable("employees", "*", "full_name", true),
      selectTable("job_assignments", "*", "created_at", false),
      selectTable("timesheets", "*", "work_date", false),
      selectTable("documents", "*", "last_synced_at", false)
    ]);

    state.data.clients = clients;
    state.data.jobs = jobs;
    state.data.costTrackers = costTrackers;
    state.data.invoices = invoices;
    state.data.employees = employees;
    state.data.assignments = assignments;
    state.data.timesheets = timesheets;
    state.data.documents = documents;

    hydrateSelects();
    renderAll();
    showToast("Dashboard data refreshed.");
  } catch (error) {
    showToast(error.message, true);
  }
}

async function selectTable(table, columns = "*", orderColumn = "created_at", ascending = false) {
  const { data, error } = await state.supabase
    .from(table)
    .select(columns)
    .order(orderColumn, { ascending })
    .limit(500);

  if (error) {
    if (["employees", "job_assignments", "timesheets"].includes(table)) {
      console.warn(`${table} not available yet:`, error.message);
      return [];
    }

    throw error;
  }

  return data || [];
}

function showView(viewName) {
  state.view = viewName;

  $$(".view").forEach((view) => view.classList.remove("active"));
  $(`#${viewName}View`).classList.add("active");

  $$(".nav-btn").forEach((button) => {
    button.classList.toggle("active", button.dataset.view === viewName);
  });

  const titles = {
    dashboard: "Dashboard",
    jobs: "Jobs",
    costTrackers: "Cost Trackers",
    invoices: "Invoices",
    timesheets: "Timesheets",
    employees: "Employees",
    assignments: "Job Assignments",
    documents: "Documents"
  };

  $("#viewTitle").textContent = titles[viewName] || "Dashboard";
}

function renderAll() {
  renderStats();
  renderDashboardLists();
  renderJobs();
  renderCostTrackers();
  renderInvoices();
  renderEmployees();
  renderAssignments();
  renderTimesheets();
  renderDocuments();
}

function getActiveSearchTerm() {
  const searchByView = {
    jobs: "#jobsSearch",
    costTrackers: "#costTrackersSearch",
    invoices: "#invoicesSearch",
    timesheets: "#timesheetsSearch",
    employees: "#employeesSearch",
    assignments: "#assignmentsSearch",
    documents: "#documentsSearch"
  };
  const localSearch = $(searchByView[state.view] || "");
  if (localSearch) return localSearch.value.toLowerCase().trim();
  const globalSearch = $("#globalSearch");
  return globalSearch ? globalSearch.value.toLowerCase().trim() : "";
}

function filtered(items, fields) {
  const term = getActiveSearchTerm();

  if (!term) return items;

  return items.filter((item) =>
    fields
      .map((field) => item[field] || "")
      .join(" ")
      .toLowerCase()
      .includes(term)
  );
}

function renderStats() {
  const { jobs, costTrackers, invoices } = state.data;

  const activeJobs = jobs.filter((job) => (job.status || "").toLowerCase() === "active").length;

  const quoted = costTrackers.reduce((sum, row) => sum + costTrackerQuoted(row), 0);
  const totalCost = costTrackers.reduce((sum, row) => sum + costTrackerTotal(row), 0);
  const profit = costTrackers.reduce((sum, row) => sum + costTrackerProfit(row), 0);

  const openInvoices = invoices
    .filter((invoice) => !["paid", "cancelled"].includes((invoice.status || "").toLowerCase()))
    .reduce((sum, row) => sum + number(row.subtotal) + number(row.tax), 0);

  $("#statJobs").textContent = jobs.length;
  $("#statActiveJobs").textContent = activeJobs;
  $("#statQuoted").textContent = money(quoted);
  $("#statCost").textContent = money(totalCost);
  $("#statProfit").textContent = money(profit);
  $("#statOpenInvoices").textContent = money(openInvoices);
}

function renderDashboardLists() {
  const recentJobs = state.data.jobs.slice(0, 6);

  const openInvoices = state.data.invoices
    .filter((invoice) => !["paid", "cancelled"].includes((invoice.status || "").toLowerCase()))
    .slice(0, 6);

  $("#recentJobs").innerHTML = createMiniCardList(
    recentJobs,
    (job) => `
      <strong>${escapeHtml(job.job_number || "-")} — ${escapeHtml(job.job_name || "-")}</strong>
      <span>${escapeHtml(job.company_name || "-")} • ${escapeHtml(job.location || "-")}</span>
      <span class="status ${escapeHtml(job.status || "")}">${escapeHtml(job.status || "unknown")}</span>
    `
  );

  $("#openInvoices").innerHTML = createMiniCardList(
    openInvoices,
    (invoice) => {
      const job = findJob(invoice.job_id);

      return `
        <strong>${escapeHtml(invoice.invoice_number || "-")} — ${money(number(invoice.subtotal) + number(invoice.tax))}</strong>
        <span>${escapeHtml(job?.job_number || "-")} • Due ${formatDate(invoice.due_date)}</span>
        <span class="status ${escapeHtml(invoice.status || "")}">${escapeHtml(invoice.status || "draft")}</span>
      `;
    }
  );
}

function createMiniCardList(items, renderer) {
  if (!items.length) return `<p class="muted">No records yet.</p>`;

  return `
    <div class="card-list">
      ${items.map((item) => `<article class="mini-card">${renderer(item)}</article>`).join("")}
    </div>
  `;
}

