/* ==========================================================================
   COST TRACKER ASSIGNMENT + CLEAN TABLE OVERRIDES
   --------------------------------------------------------------------------
   Final workflow polish:
   - Assign/change a cost tracker's job directly from the Cost Trackers table.
   - Create a job from an unassigned tracker and automatically connect it.
   - Keep cost trackers independent records; assigning a job never merges them.
   ========================================================================== */

function ensureEditableFormFields() {
  ensureHiddenInput("#jobForm", "record_id");
  ensureHiddenInput("#jobForm", "pending_cost_tracker_id");
  ensureHiddenInput("#employeeForm", "record_id");
  ensureHiddenInput("#costTrackerForm", "record_id");
}

function buildInlineJobAssignmentControl(tracker) {
  const options = [
    `<option value="">Unassigned</option>`,
    ...state.data.jobs.map((job) => {
      const selected = job.id === tracker.job_id ? " selected" : "";
      const label = `${job.job_number || "No #"} — ${job.job_name || "Untitled"}`;
      return `<option value="${escapeAttr(job.id)}"${selected}>${escapeHtml(label)}</option>`;
    })
  ].join("");

  const assignText = tracker.job_id ? "Update Job" : "Assign Job";
  const createJobButton = !tracker.job_id
    ? `<button class="link-btn assign-secondary" data-create-job-from-cost="${escapeAttr(tracker.id)}" type="button">Create Job</button>`
    : "";

  return `
    <div class="inline-assign-control">
      <select class="assign-job-select" data-assign-job-select="${escapeAttr(tracker.id)}" aria-label="Assign job to ${escapeAttr(getTrackerName(tracker))}">
        ${options}
      </select>
      <div class="inline-assign-actions">
        <button class="link-btn" data-quick-assign-cost="${escapeAttr(tracker.id)}" type="button">${assignText}</button>
        ${createJobButton}
      </div>
    </div>
  `;
}

function buildTrackerAssignmentSnapshot(tracker, jobId) {
  const job = jobId ? findJob(jobId) : null;
  const trackerName = getTrackerName(tracker);
  const summary = {
    ...costTrackerSummary(tracker),
    trackerName,
    assignmentStatus: job ? "assigned" : "unassigned"
  };

  if (job && !summary.totalJobDays) {
    summary.totalJobDays = number(job.total_job_days || calculateJobDays(job.start_date, job.end_date));
  }

  const printableJob = job || {
    job_number: "Unassigned",
    job_name: trackerName,
    company_name: "",
    contact_name: "",
    location: "",
    total_job_days: summary.totalJobDays || null
  };

  const html = renderCostTrackerHtml({
    job: printableJob,
    items: Array.isArray(tracker.line_items) ? tracker.line_items : [],
    summary,
    notes: tracker.notes || ""
  });

  return { job, summary, html };
}

async function quickAssignCostTracker(trackerId, jobId) {
  if (!state.supabase || !state.session) {
    showToast("Sign in and connect Supabase before assigning cost trackers.", true);
    return;
  }

  const tracker = state.data.costTrackers.find((row) => row.id === trackerId);
  if (!tracker) {
    showToast("Cost tracker not found. Refresh and try again.", true);
    return;
  }

  const { summary, html } = buildTrackerAssignmentSnapshot(tracker, jobId);
  const trackerName = getTrackerName(tracker);

  try {
    const updated = await updateRow("cost_trackers", tracker.id, {
      job_id: jobId || null,
      summary,
      html_snapshot: html,
      download_filename: safeFileName(`${trackerName}-cost-tracker.html`),
      last_synced_at: new Date().toISOString()
    });

    mergeStateRow("costTrackers", updated);
    await loadAllData({ silent: true });
    refreshWebsiteLists();
    showToast(jobId ? "Cost tracker assigned to the selected job." : "Cost tracker changed back to unassigned.");
  } catch (error) {
    showToast(error.message || String(error), true);
  }
}

function loadJobFormForTracker(trackerId) {
  const tracker = state.data.costTrackers.find((row) => row.id === trackerId);
  if (!tracker) {
    showToast("Cost tracker not found. Refresh and try again.", true);
    return;
  }

  showView("jobs");
  resetJobFormMode();
  const form = $("#jobForm");
  if (!form) return;

  ensureHiddenInput("#jobForm", "pending_cost_tracker_id");
  setFormValue(form, "pending_cost_tracker_id", tracker.id || "");
  setFormValue(form, "job_name", getTrackerName(tracker));
  setFormValue(form, "status", "active");
  setFormValue(form, "total_job_days", costTrackerSummary(tracker).totalJobDays || "");

  const title = $("#jobFormTitle");
  const submit = $("#jobSubmitBtn");
  if (title) title.textContent = "Create Job for Cost Tracker";
  if (submit) submit.textContent = "Create Job and Assign Tracker";

  form.scrollIntoView({ behavior: "smooth", block: "start" });
  showToast("Enter the job number and job information, then save. This tracker will be assigned automatically.");
}

async function handleCreateJob(event) {
  event.preventDefault();

  if (!state.supabase || !state.session) {
    showToast("Sign in and connect Supabase before creating jobs.", true);
    return;
  }

  const form = event.currentTarget;
  syncJobTotalDaysField();
  const values = formToObject(form);
  const editingId = values.record_id || "";
  const pendingTrackerId = values.pending_cost_tracker_id || "";

  try {
    const client = await upsertClient(values.company_name, values.contact_name);
    const payload = buildJobPayload(values, client);
    const job = await saveJobToSupabase(payload, editingId);

    mergeStateRow("jobs", job);

    if (pendingTrackerId && !editingId) {
      const tracker = state.data.costTrackers.find((row) => row.id === pendingTrackerId);
      if (tracker) {
        const { summary, html } = buildTrackerAssignmentSnapshot(tracker, job.id);
        const updatedTracker = await updateRow("cost_trackers", tracker.id, {
          job_id: job.id,
          summary,
          html_snapshot: html,
          last_synced_at: new Date().toISOString()
        });
        mergeStateRow("costTrackers", updatedTracker);
      }
    }

    hydrateSelects();
    refreshWebsiteLists();

    form.reset();
    resetJobFormMode();
    await loadAllData({ silent: true });
    refreshWebsiteLists();

    if (pendingTrackerId && !editingId) {
      showToast("Job saved and the unassigned cost tracker was assigned to it.");
    } else {
      showToast(editingId ? "Job updated and saved to Supabase." : "Job saved to Supabase. Create or assign a cost tracker when you are ready.");
    }
  } catch (error) {
    showToast(error.message || String(error), true);
  }
}

