function handleCostInvoiceTableActions(event) {
  const quickAssignCostId = event.target.closest("[data-quick-assign-cost]")?.dataset.quickAssignCost;
  const createJobFromCostId = event.target.closest("[data-create-job-from-cost]")?.dataset.createJobFromCost;

  if (quickAssignCostId) {
    const select = Array.from(document.querySelectorAll("[data-assign-job-select]")).find((node) => node.dataset.assignJobSelect === quickAssignCostId);
    quickAssignCostTracker(quickAssignCostId, select?.value || "");
    return;
  }

  if (createJobFromCostId) {
    loadJobFormForTracker(createJobFromCostId);
    return;
  }

  const editJobId = event.target.closest("[data-edit-job]")?.dataset.editJob;
  const editEmployeeId = event.target.closest("[data-edit-employee]")?.dataset.editEmployee;
  const editCostId = event.target.closest("[data-edit-cost]")?.dataset.editCost;
  const previewCostId = event.target.closest("[data-preview-cost]")?.dataset.previewCost;
  const downloadCostId = event.target.closest("[data-download-cost]")?.dataset.downloadCost;
  const invoiceCostId = event.target.closest("[data-invoice-from-cost]")?.dataset.invoiceFromCost;
  const editInvoiceId = event.target.closest("[data-edit-invoice]")?.dataset.editInvoice;
  const previewInvoiceId = event.target.closest("[data-preview-invoice]")?.dataset.previewInvoice;
  const downloadInvoiceId = event.target.closest("[data-download-invoice]")?.dataset.downloadInvoice;
  const openCostJobId = event.target.closest("[data-open-cost-for-job]")?.dataset.openCostForJob;
  const openInvoiceJobId = event.target.closest("[data-open-invoice-for-job]")?.dataset.openInvoiceForJob;

  if (editJobId) {
    const job = state.data.jobs.find((row) => row.id === editJobId);
    if (job) loadJobIntoForm(job);
    return;
  }

  if (editEmployeeId) {
    const employee = state.data.employees.find((row) => row.id === editEmployeeId);
    if (employee) loadEmployeeIntoForm(employee);
    return;
  }

  if (editCostId) {
    const tracker = state.data.costTrackers.find((row) => row.id === editCostId);
    if (tracker) loadCostTrackerIntoForm(tracker);
    return;
  }

  if (previewCostId) {
    const tracker = state.data.costTrackers.find((row) => row.id === previewCostId);
    if (tracker) previewSavedCostTracker(tracker);
    return;
  }

  if (downloadCostId) {
    const tracker = state.data.costTrackers.find((row) => row.id === downloadCostId);
    if (tracker) downloadSavedCostTracker(tracker);
    return;
  }

  if (invoiceCostId) {
    const tracker = state.data.costTrackers.find((row) => row.id === invoiceCostId);
    if (tracker) fillInvoiceFromCostTracker(tracker);
    return;
  }

  if (editInvoiceId) {
    const invoice = state.data.invoices.find((row) => row.id === editInvoiceId);
    if (invoice) loadInvoiceIntoForm(invoice);
    return;
  }

  if (previewInvoiceId) {
    const invoice = state.data.invoices.find((row) => row.id === previewInvoiceId);
    if (invoice) previewSavedInvoice(invoice);
    return;
  }

  if (downloadInvoiceId) {
    const invoice = state.data.invoices.find((row) => row.id === downloadInvoiceId);
    if (invoice) downloadSavedInvoice(invoice);
    return;
  }

  if (openCostJobId) {
    loadCostTrackerForJob(openCostJobId, true);
    return;
  }

  if (openInvoiceJobId) {
    loadInvoiceForJob(openInvoiceJobId, true);
  }
}


/* ==========================================================================
   FINAL DELETE + EMPLOYEE SAVE OVERRIDES
   --------------------------------------------------------------------------
   - Adds database-backed delete actions to every dashboard table.
   - Keeps employee creates/updates reliable and refreshes the table immediately.
   - Keeps inline cost-tracker job assignment/edit/download actions.
   ========================================================================== */

const TABLE_DELETE_CONFIG = {
  jobs: {
    table: "jobs",
    stateKey: "jobs",
    label: "job",
    getName: (row) => `${row.job_number || "Job"} ${row.job_name || ""}`.trim()
  },
  employees: {
    table: "employees",
    stateKey: "employees",
    label: "employee",
    getName: (row) => row.full_name || "employee"
  },
  costTrackers: {
    table: "cost_trackers",
    stateKey: "costTrackers",
    label: "cost tracker",
    getName: (row) => getTrackerName(row)
  },
  invoices: {
    table: "invoices",
    stateKey: "invoices",
    label: "invoice",
    getName: (row) => row.invoice_number || "invoice"
  },
  assignments: {
    table: "job_assignments",
    stateKey: "assignments",
    label: "job assignment",
    getName: () => "job assignment"
  },
  timesheets: {
    table: "timesheets",
    stateKey: "timesheets",
    label: "timesheet entry",
    getName: (row) => row.work_date || "timesheet entry"
  },
  documents: {
    table: "documents",
    stateKey: "documents",
    label: "document",
    getName: (row) => row.file_name || row.document_type || "document"
  }
};

function getDeleteConfig(type) {
  return TABLE_DELETE_CONFIG[type] || null;
}

function findStateRowByDeleteType(type, id) {
  const config = getDeleteConfig(type);
  if (!config) return null;
  return (state.data[config.stateKey] || []).find((row) => row.id === id) || null;
}

async function deleteDashboardRecord(type, id) {
  const config = getDeleteConfig(type);

  if (!config || !id) {
    showToast("Could not identify the record to delete.", true);
    return;
  }

  if (!state.supabase || !state.session) {
    showToast("Sign in and connect Supabase before deleting records.", true);
    return;
  }

  const row = findStateRowByDeleteType(type, id);
  const name = row ? config.getName(row) : config.label;
  const confirmed = window.confirm(`Delete this ${config.label}${name ? `: ${name}` : ""}?\n\nThis cannot be undone.`);

  if (!confirmed) return;

  try {
    const { error } = await state.supabase
      .from(config.table)
      .delete()
      .eq("id", id);

    if (error) throw error;

    state.data[config.stateKey] = (state.data[config.stateKey] || []).filter((row) => row.id !== id);

    if (type === "jobs") {
      state.data.costTrackers = state.data.costTrackers.map((tracker) =>
        tracker.job_id === id ? { ...tracker, job_id: null } : tracker
      );
      state.data.invoices = state.data.invoices.map((invoice) =>
        invoice.job_id === id ? { ...invoice, job_id: null } : invoice
      );
      state.data.assignments = state.data.assignments.filter((assignment) => assignment.job_id !== id);
      state.data.timesheets = state.data.timesheets.filter((entry) => entry.job_id !== id);
      state.data.documents = state.data.documents.filter((doc) => doc.job_id !== id);
    }

    if (type === "employees") {
      state.data.assignments = state.data.assignments.filter((assignment) => assignment.employee_id !== id);
      state.data.timesheets = state.data.timesheets.map((entry) =>
        entry.employee_id === id ? { ...entry, employee_id: null } : entry
      );
    }

    hydrateSelects();
    refreshWebsiteLists();
    await loadAllData({ silent: true });
    refreshWebsiteLists();
    showToast(`${capitalize(config.label)} deleted.`);
  } catch (error) {
    showToast(error.message || String(error), true);
  }
}

function capitalize(value) {
  const text = String(value || "");
  return text ? text.charAt(0).toUpperCase() + text.slice(1) : text;
}

async function handleCreateEmployee(event) {
  event.preventDefault();

  if (!state.supabase || !state.session) {
    showToast("Sign in and connect Supabase before saving employees.", true);
    return;
  }

  const form = event.currentTarget;
  const values = formToObject(form);
  const editingId = values.record_id || "";

  const payload = {
    full_name: String(values.full_name || "").trim(),
    email: values.email ? String(values.email).trim() : null,
    phone: values.phone ? String(values.phone).trim() : null,
    role: values.role || null,
    status: values.status || "active"
  };

  if (!payload.full_name) {
    showToast("Employee name is required.", true);
    return;
  }

  try {
    const employee = editingId
      ? await updateRow("employees", editingId, payload)
      : await insertRow("employees", payload);

    mergeStateRow("employees", employee);
    hydrateSelects();
    refreshWebsiteLists();
    form.reset();
    resetEmployeeFormMode();
    await loadAllData({ silent: true });
    refreshWebsiteLists();

    showToast(editingId ? "Employee updated and saved to Supabase." : "Employee added to the website table and saved to Supabase.");
  } catch (error) {
    showToast(error.message || String(error), true);
  }
}

