/* ==========================================================================
   FULL-PAGE INVOICE FIT BEHAVIOR
   --------------------------------------------------------------------------
   Scales the invoice editor/preview to fit the available screen area so the
   invoice does not create its own scrollbars while editing or viewing.
   ========================================================================== */
(function installFullPageInvoiceFit() {
  const PAGE_WIDTH = 1056;  // 11in at 96 CSS px/in
  const PAGE_HEIGHT = 816;  // 8.5in at 96 CSS px/in

  function safeNumber(value, fallback) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : fallback;
  }

  window.fitInvoiceTemplateToViewport = function fitInvoiceTemplateToViewport() {
    const wrapper = document.querySelector('.invoice-template-scroll');
    const doc = document.querySelector('#invoiceTemplateEditor.invoice-template-document');
    if (!wrapper || !doc) return;

    const rect = wrapper.getBoundingClientRect();
    const availableWidth = Math.max(320, wrapper.clientWidth - 2);
    const availableHeight = Math.max(280, window.innerHeight - rect.top - 18);
    const scale = Math.min(availableWidth / PAGE_WIDTH, availableHeight / PAGE_HEIGHT, 1.08);
    const finalScale = Math.max(0.45, safeNumber(scale, 1));

    wrapper.style.setProperty('--invoice-fit-scale', String(finalScale));
    wrapper.style.height = `${Math.ceil(PAGE_HEIGHT * finalScale) + 6}px`;
    wrapper.style.maxHeight = `${Math.ceil(PAGE_HEIGHT * finalScale) + 6}px`;
  };

  window.fitInvoicePreviewToViewport = function fitInvoicePreviewToViewport() {
    const content = document.querySelector('#invoicePreviewContent');
    const doc = content?.querySelector('.invoice-template-document');
    if (!content || !doc) return;

    const availableWidth = Math.max(320, content.clientWidth - 24);
    const availableHeight = Math.max(280, window.innerHeight - 180);
    const scale = Math.min(availableWidth / PAGE_WIDTH, availableHeight / PAGE_HEIGHT, 1);
    const finalScale = Math.max(0.45, safeNumber(scale, 1));

    content.style.setProperty('--invoice-preview-scale', String(finalScale));
    content.style.height = `${Math.ceil(PAGE_HEIGHT * finalScale) + 24}px`;
    content.style.maxHeight = `${Math.ceil(PAGE_HEIGHT * finalScale) + 24}px`;
  };

  const previousShowView = typeof showView === 'function' ? showView : null;
  if (previousShowView && !previousShowView.__invoiceFitWrapped) {
    const wrappedShowView = function invoiceFitShowView(viewName) {
      const result = previousShowView.apply(this, arguments);
      if (viewName === 'invoices') {
        requestAnimationFrame(() => window.fitInvoiceTemplateToViewport?.());
        setTimeout(() => window.fitInvoiceTemplateToViewport?.(), 60);
      }
      return result;
    };
    wrappedShowView.__invoiceFitWrapped = true;
    showView = wrappedShowView;
  }

  const previousOpenInvoicePreview = typeof openInvoicePreview === 'function' ? openInvoicePreview : null;
  if (previousOpenInvoicePreview && !previousOpenInvoicePreview.__invoiceFitWrapped) {
    const wrappedOpenInvoicePreview = function invoiceFitOpenInvoicePreview(html) {
      const result = previousOpenInvoicePreview.apply(this, arguments);
      requestAnimationFrame(() => window.fitInvoicePreviewToViewport?.());
      setTimeout(() => window.fitInvoicePreviewToViewport?.(), 60);
      return result;
    };
    wrappedOpenInvoicePreview.__invoiceFitWrapped = true;
    openInvoicePreview = wrappedOpenInvoicePreview;
  }

  window.addEventListener('resize', () => {
    window.fitInvoiceTemplateToViewport?.();
    window.fitInvoicePreviewToViewport?.();
  });

  document.addEventListener('DOMContentLoaded', () => {
    setTimeout(() => window.fitInvoiceTemplateToViewport?.(), 80);
  });

  document.addEventListener('input', (event) => {
    if (event.target.closest?.('#invoiceForm')) {
      requestAnimationFrame(() => window.fitInvoiceTemplateToViewport?.());
    }
  });
})();


/* ==========================================================================
   COST TRACKER TOTAL COST + SELECTED JOB LOADER FIX
   --------------------------------------------------------------------------
   Final override:
   - Saves total_cost, profit, and margin to Supabase using the spreadsheet
     cost tracker totals.
   - Makes the top Job / AFE dropdown load the most recent saved cost tracker
     for the selected job.
   - Adds a visible banner/flash so users can see when the loaded tracker
     changed because of a selected job or Jobs-table action.
   ========================================================================== */
(function installCostTrackerTotalAndLoaderFix() {
  const previousBuildCostTrackerPayload = typeof buildCostTrackerPayload === "function" ? buildCostTrackerPayload : null;
  const previousLoadCostTrackerIntoForm = typeof loadCostTrackerIntoForm === "function" ? loadCostTrackerIntoForm : null;
  const previousHydrateSelects = typeof hydrateSelects === "function" ? hydrateSelects : null;

  function latestDateValue(row) {
    const value = row?.updated_at || row?.last_synced_at || row?.created_at || "";
    const time = Date.parse(value);
    return Number.isFinite(time) ? time : 0;
  }

  window.findLatestCostTrackerForJob = function findLatestCostTrackerForJob(jobId) {
    if (!jobId) return null;
    return (state.data.costTrackers || [])
      .filter((tracker) => tracker.job_id === jobId)
      .sort((a, b) => latestDateValue(b) - latestDateValue(a))[0] || null;
  };

  function computedCostSummaryFromPayload(payload = {}) {
    const summary = parseJsonObject(payload.summary);
    const laborCost = number(payload.labor_cost ?? summary.laborCost ?? summary.labor_cost);
    const materialCost = number(payload.material_cost ?? summary.materialCost ?? summary.material_cost);
    const equipmentCost = number(payload.equipment_cost ?? summary.equipmentCost ?? summary.equipment_cost);
    const subcontractorCost = number(payload.subcontractor_cost ?? summary.subcontractorCost ?? summary.subcontractor_cost);
    const otherCost = number(payload.other_cost ?? summary.otherCost ?? summary.other_cost);
    const savedTotal = summary.totalCost ?? summary.total_cost;
    const totalCost = savedTotal !== undefined && savedTotal !== null && savedTotal !== ""
      ? number(savedTotal)
      : roundMoney(laborCost + materialCost + equipmentCost + subcontractorCost + otherCost);
    const quotedPrice = number(payload.quoted_price ?? summary.quotedPrice ?? summary.quoted_price);
    const profit = summary.profit !== undefined && summary.profit !== null && summary.profit !== ""
      ? number(summary.profit)
      : roundMoney(quotedPrice - totalCost);
    const margin = summary.margin !== undefined && summary.margin !== null && summary.margin !== ""
      ? number(summary.margin)
      : (quotedPrice > 0 ? profit / quotedPrice : 0);

    return {
      summary,
      totalCost: roundMoney(totalCost),
      quotedPrice: roundMoney(quotedPrice),
      profit: roundMoney(profit),
      margin: Number.isFinite(margin) ? margin : 0
    };
  }

  if (previousBuildCostTrackerPayload) {
    buildCostTrackerPayload = function buildCostTrackerPayloadWithDatabaseTotals(job, items, summary, notes = null, formValues = {}) {
      const payload = previousBuildCostTrackerPayload.call(this, job, items, summary, notes, formValues);
      const calculated = computedCostSummaryFromPayload(payload);

      payload.total_cost = calculated.totalCost;
      payload.profit = calculated.profit;
      payload.margin = calculated.margin;
      payload.summary = {
        ...calculated.summary,
        totalCost: calculated.totalCost,
        total_cost: calculated.totalCost,
        quotedPrice: calculated.quotedPrice,
        quoted_price: calculated.quotedPrice,
        profit: calculated.profit,
        margin: calculated.margin
      };

      return payload;
    };
  }

  function ensureCostTrackerNotice() {
    let notice = document.getElementById("costTrackerLoadNotice");
    if (notice) return notice;

    const form = document.getElementById("costTrackerForm");
    if (!form) return null;

    notice = document.createElement("div");
    notice.id = "costTrackerLoadNotice";
    notice.className = "cost-tracker-load-notice hidden";

    const header = form.querySelector(".sheet-page-header") || form.firstElementChild;
    if (header && header.parentNode) {
      header.insertAdjacentElement("afterend", notice);
    } else {
      form.prepend(notice);
    }

    return notice;
  }

  function setCostTrackerNotice(message, mode = "info") {
    const notice = ensureCostTrackerNotice();
    if (!notice) return;

    notice.className = `cost-tracker-load-notice ${mode}`;
    notice.innerHTML = message;
  }

  function flashCostTrackerSheet() {
    const panel = document.getElementById("costTrackerForm");
    const sheet = document.getElementById("costTrackerSheet");
    [panel, sheet].filter(Boolean).forEach((element) => {
      element.classList.remove("tracker-loaded-flash");
      // Force restart of animation.
      void element.offsetWidth;
      element.classList.add("tracker-loaded-flash");
      window.setTimeout(() => element.classList.remove("tracker-loaded-flash"), 1800);
    });
  }

  function trackerLoadedMessage(tracker, source = "saved") {
    const job = findJob(tracker?.job_id);
    const trackerName = getTrackerName(tracker);
    const jobText = job
      ? `Job <strong>${escapeHtml(job.job_number || "No #")}</strong> — ${escapeHtml(job.job_name || "Untitled")}`
      : "<strong>Unassigned</strong>";
    return `
      <strong>Loaded Cost Tracker:</strong>
      <span>${escapeHtml(trackerName)}</span>
      <em>${jobText}</em>
      <b>Total Cost: ${money(costTrackerTotal(tracker))}</b>
      ${source === "dropdown" ? "<small>Changed from the Job / AFE dropdown.</small>" : ""}
    `;
  }

  function blankTrackerMessage(job) {
    return `
      <strong>No saved cost tracker found for this job.</strong>
      <span>A blank cost tracker template is ready for <b>${escapeHtml(job.job_number || "No #")}</b> — ${escapeHtml(job.job_name || "Untitled")}.</span>
      <small>It will save to the database when you click Save Cost Tracker.</small>
    `;
  }

  window.markCostTrackerLoadedNotice = function markCostTrackerLoadedNotice(tracker, source = "saved") {
    if (!tracker) return;
    setCostTrackerNotice(trackerLoadedMessage(tracker, source), "success");
    flashCostTrackerSheet();
  };

  if (previousLoadCostTrackerIntoForm) {
    loadCostTrackerIntoForm = function loadCostTrackerIntoFormWithVisibleNotice(tracker, options = {}) {
      const result = previousLoadCostTrackerIntoForm.call(this, tracker);
      markCostTrackerLoadedNotice(tracker, options.source || "saved");
      return result;
    };
  }

  loadCostTrackerForJob = function loadCostTrackerForJobWithSavedTrackerLookup(jobId, announce = true) {
    const form = document.getElementById("costTrackerForm");

    if (!jobId) {
      showView("costTrackers");
      resetCostTrackerForm(false);
      updateCostSheetHeaderFromSelectedJob();
      setCostTrackerNotice("<strong>No job selected.</strong><span>You can create or edit an unassigned cost tracker.</span>", "info");
      return;
    }

    const job = findJob(jobId);
    if (!job) {
      showToast("Selected job was not found. Refresh the dashboard and try again.", true);
      return;
    }

    const savedTracker = findLatestCostTrackerForJob(jobId);
    if (savedTracker) {
      loadCostTrackerIntoForm(savedTracker, { source: "dropdown" });
      if (announce) {
        showToast(`Loaded "${getTrackerName(savedTracker)}" for job ${job.job_number || job.job_name || ""}.`);
      }
      return;
    }

    showView("costTrackers");
    resetCostTrackerForm(false);
    setFormValue(form, "job_id", job.id);
    setFormValue(form, "cost_tracker_name", `${job.job_number || "Job"} Cost Tracker`);
    setFormValue(form, "total_job_days", job.total_job_days || calculateJobDays(job.start_date, job.end_date) || "");
    populateCostTrackerFromTemplateForJob(job);
    updateCostSheetHeaderFromSelectedJob();
    recomputeCostTrackerTotals();
    setCostTrackerNotice(blankTrackerMessage(job), "warning");
    flashCostTrackerSheet();

    if (announce) {
      showToast("No saved cost tracker exists for this job yet. A blank template is ready.");
    }
  };

  hydrateSelects = function hydrateSelectsWithCostTrackerAvailability() {
    const jobOptions = [
      `<option value="">No job assigned...</option>`,
      ...state.data.jobs.map((job) => {
        const savedTracker = findLatestCostTrackerForJob(job.id);
        const label = `${job.job_number || "No #"} — ${job.job_name || "Untitled"}${savedTracker ? ` • Saved tracker: ${getTrackerName(savedTracker)}` : " • No tracker yet"}`;
        return `<option value="${escapeAttr(job.id)}">${escapeHtml(label)}</option>`;
      })
    ].join("");

    const employeeOptions = [
      `<option value="">Select an employee...</option>`,
      ...state.data.employees.map((employee) =>
        `<option value="${escapeAttr(employee.id)}">${escapeHtml(employee.full_name || "Unnamed")}</option>`
      )
    ].join("");

    const trackerOptions = [
      `<option value="">Select a saved cost tracker...</option>`,
      ...state.data.costTrackers.map((tracker) => {
        const job = findJob(tracker.job_id);
        const labelParts = [
          getTrackerName(tracker),
          job?.job_number ? `Job ${job.job_number}` : "Unassigned",
          money(costTrackerTotal(tracker))
        ];
        return `<option value="${escapeAttr(tracker.id)}">${escapeHtml(labelParts.join(" • "))}</option>`;
      })
    ].join("");

    document.querySelectorAll(".job-select").forEach((select) => {
      const current = select.value;
      select.innerHTML = jobOptions;
      if (current) select.value = current;
    });

    document.querySelectorAll(".employee-select").forEach((select) => {
      const current = select.value;
      select.innerHTML = employeeOptions;
      if (current) select.value = current;
    });

    document.querySelectorAll(".cost-tracker-select").forEach((select) => {
      const current = select.value;
      select.innerHTML = trackerOptions;
      if (current) select.value = current;
    });
  };

  // Refresh option labels once this patch is installed.
  if (state?.data) {
    try { hydrateSelects(); } catch {}
  }

  // Make sure direct manual job selection always routes through the saved-tracker loader
  // even if older event handlers were installed before this patch.
  document.addEventListener("change", (event) => {
    const select = event.target.closest?.('#costTrackerForm select[name="job_id"]');
    if (!select) return;
    if (select.dataset.costTrackerLoadHandled === "true") return;

    select.dataset.costTrackerLoadHandled = "true";
    window.setTimeout(() => {
      select.dataset.costTrackerLoadHandled = "";
    }, 100);

    loadCostTrackerForJob(select.value, true);
  }, true);
})();



/* ========================================================================== 
   FOREMAN DAILY TIMESHEET BUILDER + PDF TEMPLATE
   --------------------------------------------------------------------------
   Matches the uploaded Insulation Timesheet - Timecard PDF workflow:
   pick a job, auto-fill customer/job/location/date, enter employees/hours,
   save the full daily timecard to Supabase, then view/print/download as PDF.
   ========================================================================== */

(() => {
  const TIMESHEET_MAX_PRINT_ROWS = 21;
  const TIMESHEET_TABLE = "timesheets";

  function timesheetForm() {
    return document.getElementById("timesheetForm");
  }

  function timesheetRowsBody() {
    return document.getElementById("timesheetEmployeeRows");
  }

  function setTimesheetField(name, value) {
    const form = timesheetForm();
    if (!form) return;
    form.querySelectorAll(`[name="${name}"]`).forEach((input) => {
      input.value = value ?? "";
    });
  }

  function getTimesheetField(name) {
    const form = timesheetForm();
    return form?.querySelector(`[name="${name}"]`)?.value || "";
  }

  function syncTimesheetJobSelects(value) {
    const form = timesheetForm();
    if (!form) return;
    form.querySelectorAll('select[name="job_id"]').forEach((select) => {
      select.value = value || "";
    });
  }

  function clearTimesheetGroupForNewDailySheet() {
    setTimesheetField("timesheet_group_id", "");
  }

  function updateTimesheetJobSummary(job, workDate = "") {
    const summary = document.getElementById("timesheetJobSummary");
    if (!summary) return;

    if (!job) {
      summary.innerHTML = `
        <strong>No job selected</strong>
        <span>Choose a job above. The timecard below will fill customer, job number, location, and date automatically.</span>
      `;
      return;
    }

    const dateText = workDate ? formatDate(workDate) : formatDate(today());
    summary.innerHTML = `
      <strong>${escapeHtml(job.job_number || "No #")} — ${escapeHtml(job.job_name || "Untitled Job")}</strong>
      <span>${escapeHtml(job.company_name || "No customer")} • ${escapeHtml(job.location || "No location")} • Daily sheet date: ${escapeHtml(dateText)}</span>
    `;
  }

  function getEmployeeLabel(employee) {
    return employee?.full_name || employee?.name || employee?.email || "Unnamed Employee";
  }

  function getEmployeeIdentifier(employee) {
    return employee?.employee_id || employee?.emp_id || employee?.external_id || employee?.id?.slice?.(0, 8) || "";
  }

  function getAssignedEmployeesForJob(jobId, workDate = "") {
    const assignments = (state.data.assignments || []).filter((assignment) => {
      if (assignment.job_id !== jobId) return false;
      if (!workDate) return true;
      const startOk = !assignment.start_date || assignment.start_date <= workDate;
      const endOk = !assignment.end_date || assignment.end_date >= workDate;
      return startOk && endOk;
    });

    const seen = new Set();
    return assignments
      .map((assignment) => {
        const employee = findEmployee(assignment.employee_id) || {};
        return {
          employee_id: employee.id || assignment.employee_id || "",
          employee_identifier: getEmployeeIdentifier(employee),
          employee_name: getEmployeeLabel(employee),
          classification: assignment.assignment_role || employee.role || "",
          hours: "",
          tr: false,
          pd: false,
            notes: ""
        };
      })
      .filter((line) => {
        const key = line.employee_id || line.employee_name;
        if (!key || seen.has(key)) return false;
        seen.add(key);
        return true;
      });
  }

  function employeeSelectOptions(selectedId = "") {
    const employees = state.data.employees || [];
    return [
      `<option value="">Select employee...</option>`,
      ...employees.map((employee) => {
        const selected = employee.id === selectedId ? " selected" : "";
        return `<option value="${escapeAttr(employee.id)}"${selected}>${escapeHtml(getEmployeeLabel(employee))}</option>`;
      })
    ].join("");
  }

  function addTimesheetEmployeeRow(defaults = {}) {
    const tbody = timesheetRowsBody();
    if (!tbody) return;

    const row = document.createElement("tr");
    row.className = "timesheet-employee-row";
    row.innerHTML = `
      <td><input data-ts-field="employee_identifier" value="${escapeAttr(defaults.employee_identifier || "")}" placeholder="ID" /></td>
      <td>
        <select data-ts-field="employee_id" class="timesheet-employee-select">${employeeSelectOptions(defaults.employee_id || "")}</select>
        <input data-ts-field="employee_name" value="${escapeAttr(defaults.employee_name || "")}" placeholder="Employee name" />
      </td>
      <td><input data-ts-field="classification" value="${escapeAttr(defaults.classification || "")}" placeholder="Classification" /></td>
      <td><input data-ts-field="hours" type="number" min="0" step="0.25" value="${escapeAttr(defaults.hours ?? "")}" /></td>
      <td><input data-ts-field="tr" type="checkbox" ${defaults.tr ? "checked" : ""} /></td>
      <td><input data-ts-field="pd" type="checkbox" ${defaults.pd ? "checked" : ""} /></td>
      <td><input data-ts-field="notes" value="${escapeAttr(defaults.notes || "")}" placeholder="Optional" /></td>
      <td class="timesheet-row-actions"><button class="icon-btn remove-timesheet-row" type="button" aria-label="Remove employee row">×</button></td>
    `;

    tbody.appendChild(row);
    return row;
  }

  function setTimesheetRows(lines = []) {
    const tbody = timesheetRowsBody();
    if (!tbody) return;
    tbody.innerHTML = "";

    const usefulLines = Array.isArray(lines) && lines.length ? lines : [{}, {}, {}, {}, {}];
    usefulLines.forEach((line) => addTimesheetEmployeeRow(line));
  }

  function autofillTimesheetFromJob(jobId, options = {}) {
    const form = timesheetForm();
    if (!form) return;

    syncTimesheetJobSelects(jobId);
    const job = findJob(jobId);

    if (!job) {
      setTimesheetField("customer", "");
      setTimesheetField("customer_afe_no", "");
      setTimesheetField("pms_job_number", "");
      setTimesheetField("location", "");
      if (!getTimesheetField("work_date")) setTimesheetField("work_date", today());
      updateTimesheetJobSummary(null);
      setTimesheetRows([{}, {}, {}, {}, {}]);
      return;
    }

    const workDate = getTimesheetField("work_date") || today();
    setTimesheetField("work_date", workDate);
    updateTimesheetJobSummary(job, workDate);
    setTimesheetField("customer", job.company_name || "");
    setTimesheetField("customer_afe_no", job.job_number || "");
    setTimesheetField("pms_job_number", job.job_number || "");
    setTimesheetField("location", job.location || "");
    if (!getTimesheetField("description_of_services")) {
      setTimesheetField("description_of_services", job.job_name || "");
    }

    const assigned = getAssignedEmployeesForJob(jobId, workDate);
    if (!options.keepRows) {
      setTimesheetRows(assigned.length ? assigned : [{}, {}, {}, {}, {}]);
    }

    showToast(assigned.length
      ? `Timesheet filled with ${assigned.length} assigned employee${assigned.length === 1 ? "" : "s"}. Enter today's hours.`
      : "Job details filled. Add employees and hours for today.");
  }

  function handleTimesheetEmployeeSelect(select) {
    const row = select.closest(".timesheet-employee-row");
    const employee = findEmployee(select.value);
    if (!row || !employee) return;

    row.querySelector('[data-ts-field="employee_identifier"]').value = getEmployeeIdentifier(employee);
    row.querySelector('[data-ts-field="employee_name"]').value = getEmployeeLabel(employee);
    row.querySelector('[data-ts-field="classification"]').value = employee.role || row.querySelector('[data-ts-field="classification"]').value || "";
  }

  function extractTimesheetLines() {
    return Array.from(document.querySelectorAll("#timesheetEmployeeRows .timesheet-employee-row"))
      .map((row) => ({
        employee_id: row.querySelector('[data-ts-field="employee_id"]')?.value || "",
        employee_identifier: row.querySelector('[data-ts-field="employee_identifier"]')?.value.trim() || "",
        employee_name: row.querySelector('[data-ts-field="employee_name"]')?.value.trim() || "",
        classification: row.querySelector('[data-ts-field="classification"]')?.value.trim() || "",
        hours: number(row.querySelector('[data-ts-field="hours"]')?.value),
        tr: Boolean(row.querySelector('[data-ts-field="tr"]')?.checked),
        pd: Boolean(row.querySelector('[data-ts-field="pd"]')?.checked),
        notes: row.querySelector('[data-ts-field="notes"]')?.value.trim() || ""
      }))
      .filter((line) => line.employee_id || line.employee_name || line.employee_identifier || line.classification || line.hours > 0 || line.tr || line.pd || line.notes);
  }

  function timesheetDataFromForm() {
    const form = timesheetForm();
    const values = form ? formToObject(form) : {};
    const job = findJob(values.job_id);
    const lines = extractTimesheetLines();
    const totalHours = lines.reduce((sum, line) => sum + number(line.hours), 0);
    return {
      job_id: values.job_id || "",
      job,
      work_date: values.work_date || today(),
      customer: values.customer || job?.company_name || "",
      customer_afe_no: values.customer_afe_no || job?.job_number || "",
      pms_job_number: values.pms_job_number || job?.job_name || job?.job_number || "",
      location: values.location || job?.location || "",
      ticket_number: values.ticket_number || "",
      description_of_services: values.description_of_services || "",
      status: values.status || "submitted",
      lines,
      summary: {
        employee_count: lines.length,
        total_hours: roundMoney(totalHours)
      }
    };
  }

  function paddedTimesheetRows(lines) {
    const rows = [...lines].slice(0, TIMESHEET_MAX_PRINT_ROWS);
    while (rows.length < TIMESHEET_MAX_PRINT_ROWS) rows.push({});
    return rows;
  }

  function checkMark(value) {
    return value ? "✓" : "";
  }

  function buildTimesheetHtml(data = timesheetDataFromForm()) {
    const rows = paddedTimesheetRows(data.lines || []).map((line) => `
      <tr>
        <td>${escapeHtml(line.employee_identifier || "")}</td>
        <td>${escapeHtml(line.employee_name || "")}</td>
        <td>${escapeHtml(line.classification || "")}</td>
        <td class="hours-cell">${line.hours ? cleanNumberDisplay(line.hours) : ""}</td>
        <td class="check-cell">${checkMark(line.tr)}</td>
        <td class="check-cell">${checkMark(line.pd)}</td>
        <td>${escapeHtml(line.notes || "")}</td>
        <td></td>
      </tr>
    `).join("");

    return `
      <article class="timesheet-template-document timesheet-print-document">
        <div class="timesheet-top-rule"></div>
        <div class="timesheet-title">Foreman's Daily Time Sheet:</div>
        <div class="timesheet-logo-wrap"><img src="${window.PIMP_LOGO_DATA_URL || 'NEW_logo.png'}" alt="PIMP" /><strong>PIMP</strong></div>

        <div class="ts-label ts-customer-label">Customer:</div>
        <div class="ts-cell ts-customer-value">${escapeHtml(data.customer)}</div>
        <div class="ts-label ts-afe-label">Customer AFE / No:</div>
        <div class="ts-cell ts-afe-value">${escapeHtml(data.customer_afe_no)}</div>

        <div class="ts-label ts-pms-label">PMS Job Number:</div>
        <div class="ts-cell ts-pms-value">${escapeHtml(data.pms_job_number)}</div>
        <div class="ts-label ts-date-label">Date :</div>
        <div class="ts-cell ts-date-value">${formatDate(data.work_date)}</div>

        <div class="ts-label ts-location-label">Location:</div>
        <div class="ts-cell ts-location-value">${escapeHtml(data.location)}</div>

        <div class="ts-label ts-ticket-label">Ticket Number:</div>
        <div class="ts-cell ts-ticket-value">${escapeHtml(data.ticket_number)}</div>

        <div class="ts-label ts-description-label">Description of Services:</div>
        <div class="ts-cell ts-description-value static-multiline">${escapeHtml(data.description_of_services)}</div>

        <table class="timesheet-employee-grid">
          <thead>
            <tr>
              <th>Emp ID</th>
              <th>Emp Name</th>
              <th>Classification</th>
              <th>Hours</th>
              <th>TR</th>
              <th>PD</th>
              <th></th>
              <th></th>
            </tr>
          </thead>
          <tbody>${rows}</tbody>
        </table>
      </article>
    `;
  }

  function timesheetFileName(data = timesheetDataFromForm()) {
    const jobPart = data.customer_afe_no || data.job?.job_number || "unassigned";
    const datePart = data.work_date || today();
    const ticketPart = data.ticket_number ? `_${data.ticket_number}` : "";
    return safeFileName(`timesheet_${jobPart}_${datePart}${ticketPart}.pdf`);
  }

  function openTimesheetPreview(html) {
    const existing = document.getElementById("timesheetPreviewDialog");
    if (existing) existing.remove();

    const dialog = document.createElement("dialog");
    dialog.id = "timesheetPreviewDialog";
    dialog.className = "settings-dialog timesheet-preview-dialog";
    dialog.innerHTML = `
      <div class="settings-card timesheet-preview-card">
        <div class="panel-header">
          <h3>Timesheet Preview</h3>
          <div class="action-group">
            <button class="btn ghost" id="printTimesheetPreviewBtn" type="button">Print / Save PDF</button>
            <button class="btn ghost" id="downloadTimesheetPreviewBtn" type="button">Download PDF</button>
            <button class="btn danger" id="closeTimesheetPreviewBtn" type="button">Close</button>
          </div>
        </div>
        <div id="timesheetPreviewContent" class="timesheet-preview-content">${html}</div>
      </div>
    `;
    document.body.appendChild(dialog);
    dialog.showModal();

    dialog.querySelector("#closeTimesheetPreviewBtn").addEventListener("click", () => dialog.close());
    dialog.querySelector("#printTimesheetPreviewBtn").addEventListener("click", () => printHtmlDocument(html, "Timesheet"));
    dialog.querySelector("#downloadTimesheetPreviewBtn").addEventListener("click", () => downloadTimesheetPdfFromHtml(html));
    dialog.addEventListener("close", () => dialog.remove());
  }

  async function downloadTimesheetPdfFromHtml(html, filename = "") {
    const data = timesheetDataFromForm();
    const fileName = filename || timesheetFileName(data);

    if (!window.html2pdf) {
      showToast("PDF library was unavailable. Refresh and try again.", true);
      return;
    }

    const wrapper = document.createElement("div");
    wrapper.className = "pdf-workbench timesheet-pdf-workbench";
    wrapper.innerHTML = html;
    document.body.appendChild(wrapper);

    const element = wrapper.querySelector(".timesheet-template-document") || wrapper;
    try {
      await window.html2pdf()
        .set({
          margin: 0,
          filename: safeFileName(fileName),
          image: { type: "jpeg", quality: 0.98 },
          html2canvas: { scale: 2, useCORS: true, backgroundColor: "#ffffff" },
          jsPDF: { unit: "in", format: "letter", orientation: "portrait" }
        })
        .from(element)
        .save();
      showToast("Timesheet PDF downloaded.");
    } catch (error) {
      showToast("Timesheet PDF download failed. Refresh and try again.", true);
    } finally {
      wrapper.remove();
    }
  }

  window.previewTimesheetFromForm = function previewTimesheetFromForm() {
    const data = timesheetDataFromForm();
    if (!data.job_id) {
      showToast("Select a job before previewing the timesheet.", true);
      return;
    }
    openTimesheetPreview(buildTimesheetHtml(data));
  };

  window.downloadTimesheetFromForm = async function downloadTimesheetFromForm() {
    const data = timesheetDataFromForm();
    if (!data.job_id) {
      showToast("Select a job before downloading the timesheet.", true);
      return;
    }
    await downloadTimesheetPdfFromHtml(buildTimesheetHtml(data), timesheetFileName(data));
  };

  async function saveTimesheetDailySheet(event) {
    event.preventDefault();

    if (!state.supabase || !state.session) {
      showToast("Sign in before saving a timesheet.", true);
      return;
    }

    const data = timesheetDataFromForm();
    if (!data.job_id) {
      showToast("Select a job before saving the timesheet.", true);
      return;
    }
    if (!data.work_date) {
      showToast("Enter a date before saving the timesheet.", true);
      return;
    }
    if (!data.lines.length) {
      showToast("Add at least one employee row before saving the timesheet.", true);
      return;
    }

    const groupId = getTimesheetField("timesheet_group_id") || `timecard:${data.job_id}:${data.work_date}:${Date.now()}:${Math.random().toString(36).slice(2, 8)}`;
    const html = buildTimesheetHtml(data);
    const filename = timesheetFileName(data);

    try {
      // Editing an already-loaded group replaces its rows with the current sheet.
      if (getTimesheetField("timesheet_group_id")) {
        await state.supabase.from(TIMESHEET_TABLE).delete().eq("timesheet_group_id", groupId);
      }

      const rows = data.lines.map((line) => ({
        timesheet_group_id: groupId,
        job_id: data.job_id,
        employee_id: line.employee_id || null,
        employee_identifier: line.employee_identifier || null,
        employee_name: line.employee_name || null,
        classification: line.classification || null,
        work_date: data.work_date,
        hours: number(line.hours),
        travel_hours: line.tr ? 1 : 0,
        per_diem: line.pd ? 1 : 0,
        tr: line.tr ? true : false,
        pd: line.pd ? true : false,
        customer: data.customer || null,
        job_number: data.customer_afe_no || null,
        location: data.location || null,
        ticket_number: data.ticket_number || null,
        description_of_services: data.description_of_services || null,
        status: data.status || "submitted",
        notes: line.notes || null,
        line_items: data.lines,
        summary: data.summary,
        html_snapshot: html,
        download_filename: filename,
        external_source: "dashboard",
        external_id: `${groupId}:${line.employee_id || line.employee_name || Math.random().toString(36).slice(2)}`,
        last_synced_at: new Date().toISOString()
      }));

      const { error } = await state.supabase.from(TIMESHEET_TABLE).insert(rows);
      if (error) throw error;

      setTimesheetField("timesheet_group_id", groupId);
      await loadAllData();
      showToast("Daily timesheet saved.");
    } catch (error) {
      showToast(error.message, true);
    }
  }

  // Override the original single-row timesheet submit handler.
  handleCreateTimesheet = saveTimesheetDailySheet;

  function parseTimesheetJson(value, fallback) {
    if (!value) return fallback;
    if (Array.isArray(value) || typeof value === "object") return value;
    try { return JSON.parse(value); } catch { return fallback; }
  }

  function groupSavedTimesheets() {
    const groups = new Map();
    (state.data.timesheets || []).forEach((entry) => {
      const key = entry.timesheet_group_id || entry.id;
      if (!groups.has(key)) {
        groups.set(key, {
          id: key,
          rows: [],
          first: entry,
          lineItems: parseTimesheetJson(entry.line_items, null)
        });
      }
      groups.get(key).rows.push(entry);
    });

    return Array.from(groups.values()).map((group) => {
      const first = group.first;
      const lines = Array.isArray(group.lineItems) && group.lineItems.length
        ? group.lineItems
        : group.rows.map((row) => ({
            employee_id: row.employee_id || "",
            employee_identifier: row.employee_identifier || "",
            employee_name: row.employee_name || findEmployee(row.employee_id)?.full_name || "",
            classification: row.classification || "",
            hours: number(row.hours),
            tr: Boolean(row.tr || number(row.travel_hours) > 0),
            pd: Boolean(row.pd || number(row.per_diem) > 0),
            notes: row.notes || ""
          }));
      const totalHours = lines.reduce((sum, line) => sum + number(line.hours), 0);
      const job = findJob(first.job_id);
      return {
        id: group.id,
        first,
        job,
        lines,
        html: first.html_snapshot || "",
        filename: first.download_filename || "",
        date: first.work_date,
        customer: first.customer || job?.company_name || "",
        jobNumber: first.job_number || job?.job_number || "",
        location: first.location || job?.location || "",
        ticket: first.ticket_number || "",
        totalHours,
        employeeCount: lines.length
      };
    }).sort((a, b) => String(b.date || "").localeCompare(String(a.date || "")));
  }

  function timesheetDataFromSavedGroup(group) {
    const first = group.first;
    return {
      job_id: first.job_id || "",
      job: group.job,
      work_date: first.work_date || today(),
      customer: first.customer || group.job?.company_name || "",
      customer_afe_no: first.job_number || group.job?.job_number || "",
      pms_job_number: first.pms_job_number || group.job?.job_number || "",
      location: first.location || group.job?.location || "",
      ticket_number: first.ticket_number || "",
      description_of_services: first.description_of_services || first.notes || "",
      status: first.status || "submitted",
      lines: group.lines,
      summary: {
        employee_count: group.employeeCount,
        total_hours: group.totalHours
      }
    };
  }

  function renderSavedTimesheetHtml(group) {
    return group.html || buildTimesheetHtml(timesheetDataFromSavedGroup(group));
  }

  renderTimesheets = function renderTimesheetsGroupedDailySheets() {
    const table = document.getElementById("timesheetsTable");
    const count = document.getElementById("timesheetsCount");
    if (!table || !count) return;

    const groups = groupSavedTimesheets();
    count.textContent = groups.length;

    table.innerHTML = groups.map((group) => `
      <tr>
        <td data-label="Date">${formatDate(group.date)}</td>
        <td data-label="Customer"><strong>${escapeHtml(group.customer || "-")}</strong></td>
        <td data-label="Job">${escapeHtml(group.jobNumber || "-")}<br><span class="muted">${escapeHtml(group.job?.job_name || "")}</span></td>
        <td data-label="Location">${escapeHtml(group.location || "-")}</td>
        <td data-label="Employees" class="money-cell">${number(group.employeeCount)}</td>
        <td data-label="Total Hours" class="money-cell">${cleanNumberDisplay(group.totalHours)}</td>
        <td data-label="Ticket #">${escapeHtml(group.ticket || "-")}</td>
        <td data-label="Actions" class="table-actions">
          <button class="link-btn" data-view-timesheet-group="${escapeAttr(group.id)}" type="button">Preview</button>
          <button class="link-btn" data-download-timesheet-group="${escapeAttr(group.id)}" type="button">Download</button>
          <button class="link-btn danger-text" data-delete-timesheet-group="${escapeAttr(group.id)}" type="button">Delete</button>
        </td>
      </tr>
    `).join("") || emptyRow(8);
  };

  async function deleteTimesheetGroup(groupId) {
    if (!groupId || !state.supabase) return;
    if (!window.confirm("Delete this saved daily timesheet?")) return;

    try {
      const { error } = await state.supabase.from(TIMESHEET_TABLE).delete().eq("timesheet_group_id", groupId);
      if (error) throw error;
      state.data.timesheets = state.data.timesheets.filter((entry) => (entry.timesheet_group_id || entry.id) !== groupId);
      renderTimesheets();
      showToast("Timesheet deleted.");
    } catch (error) {
      showToast(error.message, true);
    }
  }

  function getSavedTimesheetGroupById(groupId) {
    return groupSavedTimesheets().find((group) => group.id === groupId);
  }

  function initializeTimesheetBuilder() {
    const form = timesheetForm();
    if (!form) return;

    if (!getTimesheetField("work_date")) setTimesheetField("work_date", today());
    if (!timesheetRowsBody()?.children.length) setTimesheetRows([{}, {}, {}, {}, {}]);

    const addButton = document.getElementById("addTimesheetEmployeeBtn");
    if (addButton && !addButton.dataset.bound) {
      addButton.dataset.bound = "true";
      addButton.addEventListener("click", () => addTimesheetEmployeeRow({}));
    }

    const newDayButton = document.getElementById("newTimesheetDayBtn");
    if (newDayButton && !newDayButton.dataset.bound) {
      newDayButton.dataset.bound = "true";
      newDayButton.addEventListener("click", () => {
        clearTimesheetGroupForNewDailySheet();
        setTimesheetField("ticket_number", "");
        setTimesheetField("description_of_services", "");
        const selectedJob = getTimesheetField("job_id");
        if (!getTimesheetField("work_date")) setTimesheetField("work_date", today());
        if (selectedJob) {
          autofillTimesheetFromJob(selectedJob, { keepRows: false });
          setTimesheetField("description_of_services", "");
          showToast("Ready for a new daily timesheet for the selected job/date.");
        } else {
          setTimesheetRows([{}, {}, {}, {}, {}]);
          updateTimesheetJobSummary(null);
          showToast("Ready for a new daily timesheet. Select a job to start.");
        }
      });
    }

    const previewButton = document.getElementById("previewTimesheetBtn");
    if (previewButton && !previewButton.dataset.bound) {
      previewButton.dataset.bound = "true";
      previewButton.addEventListener("click", window.previewTimesheetFromForm);
    }

    const downloadButton = document.getElementById("downloadTimesheetPdfBtn");
    if (downloadButton && !downloadButton.dataset.bound) {
      downloadButton.dataset.bound = "true";
      downloadButton.addEventListener("click", window.downloadTimesheetFromForm);
    }

    form.addEventListener("change", (event) => {
      const target = event.target;
      if (target.matches('select[name="job_id"]')) {
        clearTimesheetGroupForNewDailySheet();
        autofillTimesheetFromJob(target.value);
        setTimesheetField("description_of_services", "");
      }
      if (target.matches('[name="work_date"]')) {
        clearTimesheetGroupForNewDailySheet();
        const selectedJob = getTimesheetField("job_id");
        if (selectedJob) {
          autofillTimesheetFromJob(selectedJob, { keepRows: false });
          setTimesheetField("description_of_services", "");
        }
        else updateTimesheetJobSummary(null);
      }
      if (target.matches(".timesheet-employee-select")) {
        handleTimesheetEmployeeSelect(target);
      }
    });

    form.addEventListener("click", (event) => {
      const remove = event.target.closest(".remove-timesheet-row");
      if (remove) {
        remove.closest("tr")?.remove();
      }
    });
  }

  document.addEventListener("DOMContentLoaded", initializeTimesheetBuilder);

  document.addEventListener("click", async (event) => {
    const viewId = event.target.closest("[data-view-timesheet-group]")?.dataset.viewTimesheetGroup;
    const downloadId = event.target.closest("[data-download-timesheet-group]")?.dataset.downloadTimesheetGroup;
    const deleteId = event.target.closest("[data-delete-timesheet-group]")?.dataset.deleteTimesheetGroup;

    if (viewId) {
      const group = getSavedTimesheetGroupById(viewId);
      if (group) openTimesheetPreview(renderSavedTimesheetHtml(group));
    }

    if (downloadId) {
      const group = getSavedTimesheetGroupById(downloadId);
      if (group) await downloadTimesheetPdfFromHtml(renderSavedTimesheetHtml(group), group.filename || `timesheet_${downloadId}.pdf`);
    }

    if (deleteId) {
      await deleteTimesheetGroup(deleteId);
    }
  });

  // Keep the styled job picker hydrated and its summary current after global select hydration.
  const previousHydrateSelectsForTimesheets = hydrateSelects;
  hydrateSelects = function hydrateSelectsWithTimesheetControls() {
    previousHydrateSelectsForTimesheets.call(this);
    const form = timesheetForm();
    if (!form) return;
    const primary = form.querySelector('select[name="job_id"]');
    if (primary) {
      const job = findJob(primary.value);
      updateTimesheetJobSummary(job, getTimesheetField("work_date") || today());
    }
  };
})();

